import{_ as a,o as c,c as r,a2 as o}from"./chunks/framework.BKG_UbFK.js";const p=JSON.parse('{"title":"الأمان","description":"","frontmatter":{},"headers":[],"relativePath":"ar/guide/security.md","filePath":"ar/guide/security.md"}'),d={name:"ar/guide/security.md"};function t(l,e,i,s,n,h){return c(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="الأمان" tabindex="-1">الأمان <a class="header-anchor" href="#الأمان" aria-label="Permalink to &quot;الأمان&quot;">​</a></h1><p>خضعت Clearance لتدقيق أمني مخصص قبل النشر بالإضافة إلى جولتين متابعة لتحصين إضافي قبل الإصدار. أبرز النقاط: حدود سقفية لمنع تصعيد الصلاحيات على كل مسار يمنح صلاحية (المنح المباشر ومزامنة الصلاحيات على مستوى الدور على حد سواء)، وتجاوزات سياقية ذات أولوية للرفض، ومُعقِّم SVG بقائمة سماح، ومساحة أسماء <code>clearance-*</code> محمية، وتوجيهات Blade آمنة للضيوف.</p><h2 id="الوصول-إلى-اللوحة-وصلاحيات-الكتابة-الدقيقة-التحكم" tabindex="-1">الوصول إلى اللوحة وصلاحيات الكتابة الدقيقة التحكم <a class="header-anchor" href="#الوصول-إلى-اللوحة-وصلاحيات-الكتابة-الدقيقة-التحكم" aria-label="Permalink to &quot;الوصول إلى اللوحة وصلاحيات الكتابة الدقيقة التحكم&quot;">​</a></h2><p>يتطلب الوصول للقراءة إلى اللوحة بأكملها صلاحية <code>clearance-access</code> (يُتحقق منها عبر <code>can()</code>، وليس أبداً عبر <code>hasRole()</code>). عمليات الكتابة على كل قسم مقيّدة بصلاحية مخصصة قابلة للتفويض - جميعها تُنشأ بواسطة <code>clearance:install</code> وتُعيَّن لـ <code>super_admin</code>:</p><table tabindex="0"><thead><tr><th>الصلاحية</th><th>تتحكم في</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>إنشاء / تعديل / حذف الصلاحيات</td></tr><tr><td><code>clearance-roles-write</code></td><td>إنشاء / تعديل / حذف الأدوار وتعييناتها الخاصة بالصلاحيات</td></tr><tr><td><code>clearance-guards-write</code></td><td>إنشاء / تعديل / حذف الحراس</td></tr><tr><td><code>clearance-settings-write</code></td><td>تعديل بيانات العرض الوصفية، والأيقونات، والألوان، والدور الافتراضي</td></tr><tr><td><code>clearance-users-write</code></td><td>تعيين / إزالة الأدوار لمستخدم محدد</td></tr></tbody></table><p>إذا لم يكن صف صلاحية دقيق التحكم موجوداً على الإطلاق في قاعدة البيانات (حالة قديمة سابقة للتزويد)، يعود الفحص إلى <code>clearance-access</code> للتوافق مع الإصدارات السابقة.</p><h2 id="مساحة-أسماء-clearance-المحمية" tabindex="-1">مساحة أسماء <code>clearance-*</code> المحمية <a class="header-anchor" href="#مساحة-أسماء-clearance-المحمية" aria-label="Permalink to &quot;مساحة أسماء `clearance-*` المحمية&quot;">​</a></h2><p>صلاحيات <code>clearance-*</code> محجوزة: لا يمكن إنشاؤها، أو إعادة تسميتها، أو حذفها، أو إضافتها إلى أي دور إلا عبر تدفق التثبيت الخاص بالحزمة نفسها - حتى بواسطة ممثل (actor) من نوع <code>super_admin</code> لدور <code>super_admin</code> نفسه.</p><h2 id="حدود-سقفية-لمنع-تصعيد-الصلاحيات" tabindex="-1">حدود سقفية لمنع تصعيد الصلاحيات <a class="header-anchor" href="#حدود-سقفية-لمنع-تصعيد-الصلاحيات" aria-label="Permalink to &quot;حدود سقفية لمنع تصعيد الصلاحيات&quot;">​</a></h2><p>كل مسار يمنح صلاحية في Clearance يفرض سقفاً بحيث لا يمكن لممثل (actor) أن يمنح أكثر مما يحمله هو نفسه:</p><ul><li><strong>الأدوار السقفية (Ceiling roles)</strong> - يمكن لدور ما أن يعلن عن دور أب تُشكّل مجموعة صلاحياته حداً أعلى. يُقلَّم أي فائض من الصلاحيات بصمت عند <code>RoleService::setParent()</code> وعند كل مزامنة صلاحيات لاحقة - دون استثناء، ودون رسالة خطأ. إزالة صلاحيات من دور أب تتسلسل الإزالة إلى كل دور فرعي تلقائياً. انظر <a href="/clearance-docs/ar/features/roles.html">الأدوار</a> لواجهة الـ API الكاملة للسقف.</li><li><strong>وحدة المستخدمين</strong> - يفرض تعيين الأدوار ومنح الصلاحيات المباشر/التجاوزات على حد سواء سقفاً لمنع تصعيد الصلاحيات: لا يمكن لممثل غير <code>super_admin</code> تعديل تعييناته الخاصة، ولا يمكنه منح صلاحية لا يحملها هو نفسه. انظر <a href="/clearance-docs/ar/features/users.html">المستخدمون</a>.</li></ul><h2 id="تجاوزات-سياقية-ذات-أولوية-للرفض" tabindex="-1">تجاوزات سياقية ذات أولوية للرفض <a class="header-anchor" href="#تجاوزات-سياقية-ذات-أولوية-للرفض" aria-label="Permalink to &quot;تجاوزات سياقية ذات أولوية للرفض&quot;">​</a></h2><p>تدعم التجاوزات السياقية للصلاحيات (<code>clr_ctx_overrides</code>) نوعي <code>forced_on</code> و<code>forced_off</code>. تفوز <code>forced_off</code> دائماً - حتى على صلاحية ممنوحة من دور عام. لا يوجد مسار يسمح لمنح ذي أولوية أقل بتجاوز رفض صريح. انظر <a href="/clearance-docs/ar/guide/architecture.html#how-resolution-works">البنية المعمارية</a> لترتيب التحليل الكامل.</p><h2 id="تعقيم-svg" tabindex="-1">تعقيم SVG <a class="header-anchor" href="#تعقيم-svg" aria-label="Permalink to &quot;تعقيم SVG&quot;">​</a></h2><p>كل أيقونة يقدّمها المستخدم (بيانات عرض الدور/الحارس الوصفية في لوحة الإعدادات) تمر عبر مُعقِّم بقائمة سماح قبل التخزين وعند العرض على حد سواء - وليس مجرد فحص لمرة واحدة عند الرفع.</p><h2 id="توجيهات-blade-آمنة-للضيوف" tabindex="-1">توجيهات Blade آمنة للضيوف <a class="header-anchor" href="#توجيهات-blade-آمنة-للضيوف" aria-label="Permalink to &quot;توجيهات Blade آمنة للضيوف&quot;">​</a></h2><p>تُحلَّل كل من <code>@canin</code> و<code>@hasrolein</code> بأمان (تُرجع <code>false</code>) لمستخدم ضيف - ولا تُطلقان استثناءً أبداً.</p><h2 id="تجاوز-gate-على-مستوى-التطبيق-بأكمله" tabindex="-1">تجاوز Gate على مستوى التطبيق بأكمله <a class="header-anchor" href="#تجاوز-gate-على-مستوى-التطبيق-بأكمله" aria-label="Permalink to &quot;تجاوز Gate على مستوى التطبيق بأكمله&quot;">​</a></h2><p>يتحكم <code>super_admin_gate_bypass</code> (الافتراضي <code>false</code>) فيما إذا كان دور <code>super_admin</code> يتجاوز جميع فحوصات <code>can()</code> / <code>Gate::allows()</code> / السياسات (policies) الخاصة بـ Laravel على مستوى التطبيق بأكمله، عبر خطاف (hook) من نوع <code>Gate::before()</code>.</p><div class="warning custom-block"><p class="custom-block-title">ليس مقيّداً باللوحة</p><p>عند التفعيل، يتخطى أي مستخدم يحمل <code>super_admin</code> جميع فحوصات Gate على مستوى التطبيق بأكمله - وليس فقط فحوصات لوحة Clearance. فعّله عن قصد. انظر <a href="/clearance-docs/ar/features/super-admin.html">المشرف الفائق</a> لسلوك كشف الأسماء البديلة والترقية.</p></div><h2 id="نقاط-دقيقة-ذات-صلة-بالأمان" tabindex="-1">نقاط دقيقة ذات صلة بالأمان <a class="header-anchor" href="#نقاط-دقيقة-ذات-صلة-بالأمان" aria-label="Permalink to &quot;نقاط دقيقة ذات صلة بالأمان&quot;">​</a></h2><ul><li>تفوز <code>forced_off</code> دائماً - حتى على صلاحية ممنوحة من دور عام.</li><li>الدور السقفي يُقلّم فقط، ولا يمنح أبداً - تعيين دور أب متساهل لا يمنح الدور الفرعي أي شيء بحد ذاته.</li><li>تجاوز Gate (<code>super_admin_gate_bypass</code>) هو على مستوى التطبيق بأكمله، وليس مقيّداً باللوحة.</li><li>وحدة المستخدمين معطّلة افتراضياً (<code>modules.users = false</code>).</li><li>صلاحيات <code>clearance-*</code> غير قابلة للمس خارج تدفق التثبيت، حتى بالنسبة لـ <code>super_admin</code>.</li><li>شغّل دائماً <code>clearance:install</code>، وليس <code>migrate</code> مباشرة، على إعداد جديد - انظر <a href="/clearance-docs/ar/guide/installation.html">التثبيت</a>.</li></ul><h2 id="ذو-صلة" tabindex="-1">ذو صلة <a class="header-anchor" href="#ذو-صلة" aria-label="Permalink to &quot;ذو صلة&quot;">​</a></h2><ul><li><a href="/clearance-docs/ar/guide/architecture.html">البنية المعمارية</a> - ترتيب أولوية التحليل ومخطط <code>clr_*</code></li><li><a href="/clearance-docs/ar/features/roles.html">الأدوار</a> - الأدوار السقفية بالتفصيل</li><li><a href="/clearance-docs/ar/features/users.html">المستخدمون</a> - السقف المانع لتصعيد الصلاحيات في تعيين الأدوار/الصلاحيات</li><li><a href="/clearance-docs/ar/features/super-admin.html">المشرف الفائق</a> - تجاوز Gate وكشف الأسماء البديلة</li></ul>',24)])])}const f=a(d,[["render",t]]);export{p as __pageData,f as default};
